import java.util.List;

public class Drone implements Runnable {
    public static final float DROP_RATE = 2; //drop rate of water
    public static final float TANK_SIZE = 15; //tank size in liters
    public static final float BATTERY_SIZE = 50; //battery size in minutes
    public static final float DRONE_SPEED = 2*60; //drone speed in units per minute
    public static final float REFILL_RATE = 5; //liters refilled per second at base

    private final DroneSubsystem droneSubsystem;
    private Event event;
    private boolean running = true;
    private final DroneStateMachine stateMachine;
    private final List<Zone> zones;
    private int currentZoneId = 0;
    private int targetZoneId = 0;
    private long lastAnimDurationMs = 0;  
    private long animStartTime = 0;       
    private float waterRemaining;
    private float batteryRemaining;
    private final String droneName;

    public Drone(DroneSubsystem droneSubsystem, String droneName, List<Zone> zones) {
        this.droneSubsystem = droneSubsystem;
        this.droneName = droneName;
        this.zones = zones;
        this.stateMachine = new DroneStateMachine(droneName);
        this.waterRemaining = TANK_SIZE;
        this.batteryRemaining = BATTERY_SIZE;
        this.event = null;
    }

    public String getDroneName() {
        return droneName;
    }
    public DroneState getDroneState() {
        return stateMachine.getState();
    }
    public float getWaterRemaining() {
        return waterRemaining;
    }

    public boolean isTankEmpty() {
        return waterRemaining <= 0;
    }

    public void useUpWater(float waterVolume) {
        if(waterVolume >= waterRemaining)
            waterRemaining = 0;
        else
            waterRemaining -= waterVolume;
    }

    public void useUpBattery(float time) {
        if(time >= batteryRemaining)
            batteryRemaining = 0;
        else
            batteryRemaining -= time;
    }

    public int batteryPercent() {
        return (int)((batteryRemaining * 100) / BATTERY_SIZE);
    }
    public int getCurrentZoneId() {
        return currentZoneId;
    }
    public int getTargetZoneId() { return targetZoneId; }
    public long getLastAnimDurationMs() { return lastAnimDurationMs; }
    public long getAnimStartTime() { return animStartTime; }

    public void setDroneFull() {
        waterRemaining = TANK_SIZE;
        batteryRemaining = BATTERY_SIZE;
    }

    private float timeToZone(Zone dest) {
        Zone origin = new Zone(0, 0, 0, 0, 0); // assume origin at 0,0
        return Zone.getDistance(origin, dest) / DRONE_SPEED;
    }

    private float timeToOrigin(Zone from) {
        Zone origin = new Zone(0, 0, 0, 0, 0);
        return Zone.getDistance(from, origin) / DRONE_SPEED;
    }

    private void sendStatus() {
        try {
            droneSubsystem.sendStatus(droneName, batteryRemaining, currentZoneId, waterRemaining);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    @Override
    public void run() {
        sendStatus(); // initial status
        while(running) {
            try {
                switch(stateMachine.getState()) {
                    case idle:
                        event = droneSubsystem.requestTask(droneName);
                        event.deliverEvent(Event.State.DISPATCHED);
                        stateMachine.handleEvent(DroneEvent.fireAssigned);
                        sendStatus();
                        break;
                    case enRoute: {
                        System.out.println("[" + droneName + "] Enroute to zone " + event.getZoneID());
                        targetZoneId = event.getZoneID();
                        float travelTime = 0;
                        Zone destZone = null;
                        try {
                            destZone = Zone.getZoneFromId(zones, event.getZoneID());
                            travelTime = timeToZone(destZone);
                        } catch (Zone.UnknownZoneException ex) {
                            System.out.println("[" + droneName + "] Zone does not exist " + event.getZoneID());
                        }
                        lastAnimDurationMs = (long)(travelTime * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        if (destZone != null) {
                            System.out.println("[" + droneName + "] Travelling for " + travelTime * 60 + "s");
                            Thread.sleep(lastAnimDurationMs);
                            useUpBattery(travelTime);
                            currentZoneId = destZone.id;
                        }
                        targetZoneId = 0;
                        stateMachine.handleEvent(DroneEvent.arrivedToFire);
                        sendStatus();
                        break;
                    }
                    case droppingAgent:
                        System.out.println("[" + droneName + "] Servicing fire at zone " + event.getZoneID());
                        event.deliverEvent(Event.State.DROPPING);
                        float emptyAmount = event.getWaterLeft();
                        if(emptyAmount > waterRemaining)
                            emptyAmount = waterRemaining;
                        float emptyTime = emptyAmount / DROP_RATE;
                        Thread.sleep((int)(emptyTime * 1000));
                        useUpBattery(emptyTime);
                        useUpWater(emptyAmount);
                        event.useWater(emptyAmount);
                        if(event.getWaterLeft() <= 0) {
                            System.out.println("[" + droneName + "] Fire extinguished");
                            try {
                                droneSubsystem.reportDone(event, droneName);
                            } catch (Exception e) {
                                e.printStackTrace();
                            }
                            event.deliverEvent(Event.State.EXTINGUISHED);
                            event = null;
                            stateMachine.handleEvent(DroneEvent.jobFinished);
                        } else {
                            System.out.println("[" + droneName + "] Tank empty, need refill");
                            stateMachine.handleEvent(DroneEvent.needRefill);
                        }
                        sendStatus();
                        break;
                    case returnForRefill: {
                        float travelTimeToRefill = 0;
                        try {
                            Zone currentZoneV = Zone.getZoneFromId(zones, currentZoneId);
                            travelTimeToRefill = timeToOrigin(currentZoneV);
                        } catch(Zone.UnknownZoneException e) { }
                        lastAnimDurationMs = (long)(travelTimeToRefill * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        System.out.println("[" + droneName + "] Travelling for " + travelTimeToRefill*60 + "s");
                        Thread.sleep(lastAnimDurationMs);
                        useUpBattery(travelTimeToRefill);
                        currentZoneId = 0;
                        float waterNeeded = TANK_SIZE - waterRemaining;
                        long refillMs = (long)((waterNeeded / REFILL_RATE) * 1000);
                        System.out.println("[" + droneName + "] Refilling " + waterNeeded + "L at base");
                        Thread.sleep(refillMs);
                        setDroneFull();
                        stateMachine.handleEvent(DroneEvent.fireAssigned);
                        sendStatus();
                        break;
                    }
                    case returnOrigin: {
                        float travelTimeToOrigin = 0;
                        try {
                            Zone currentZoneV = Zone.getZoneFromId(zones, currentZoneId);
                            travelTimeToOrigin = timeToOrigin(currentZoneV);
                        } catch(Zone.UnknownZoneException e) { }
                        lastAnimDurationMs = (long)(travelTimeToOrigin * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        System.out.println("[" + droneName + "] Travelling for " + travelTimeToOrigin*60 + "s");
                        Thread.sleep(lastAnimDurationMs);
                        useUpBattery(travelTimeToOrigin);
                        currentZoneId = 0;
                        setDroneFull();
                        stateMachine.handleEvent(DroneEvent.arrivedToOrigin);
                        sendStatus();
                        break;
                    }
                    default:
                        System.out.println("[" + droneName + "] Unknown state");
                        break;
                }

            } catch (InterruptedException e) {
                System.out.println("[" + droneName + "] Interrupted");
                running = false;
                Thread.currentThread().interrupt();
            }
        }
    }
}

import java.util.List;

public class Drone implements Runnable {
    public static final float DROP_RATE = 2; //drop rate of water
    public static final float TANK_SIZE = 15; //tank size in liters
    public static final float BATTERY_SIZE = 50; //battery size in minutes
    public static final float DRONE_SPEED = 2*60; //drone speed in units per minute
    public static final float REFILL_RATE = 5; //liters refilled per second at base

    private final DroneSubsystem droneSubsystem;
    private Event event;
    private boolean running = true;
    private final DroneStateMachine stateMachine;
    private final List<Zone> zones;
    private int currentZoneId = 0;
    private int targetZoneId = 0;
    private long lastAnimDurationMs = 0;  
    private long animStartTime = 0;       
    private float waterRemaining;
    private float batteryRemaining;
    private final String droneName;
    private DroneState guiState = DroneState.idle;

    public Drone(DroneSubsystem droneSubsystem, String droneName, List<Zone> zones) {
        this.droneSubsystem = droneSubsystem;
        this.droneName = droneName;
        this.zones = zones;
        this.stateMachine = new DroneStateMachine(droneName);
        this.waterRemaining = TANK_SIZE;
        this.batteryRemaining = BATTERY_SIZE;
        this.event = null;
    }

    // Constructor for GUI updates
    public Drone(String droneName, List<Zone> zones, int currentZoneId, float waterRemaining, float batteryRemaining, int targetZoneId, long lastAnimDurationMs, long animStartTime) {
        this.droneSubsystem = null;
        this.droneName = droneName;
        this.zones = zones;
        this.stateMachine = new DroneStateMachine(droneName);
        this.currentZoneId = currentZoneId;
        this.waterRemaining = waterRemaining;
        this.batteryRemaining = batteryRemaining;
        this.targetZoneId = targetZoneId;
        this.lastAnimDurationMs = lastAnimDurationMs;
        this.animStartTime = animStartTime;
        this.event = null;
        if (targetZoneId > 0) {
            this.guiState = DroneState.enRoute;
        } else if (currentZoneId > 0) {
            this.guiState = DroneState.droppingAgent;
        } else {
            this.guiState = DroneState.idle;
        }
    }

    public String getDroneName() {
        return droneName;
    }
    public DroneState getDroneState() {
        if (droneSubsystem == null) {
            return guiState;
        }
        return stateMachine.getState();
    }
    public float getWaterRemaining() {
        return waterRemaining;
    }

    public boolean isTankEmpty() {
        return waterRemaining <= 0;
    }

    public void useUpWater(float waterVolume) {
        if(waterVolume >= waterRemaining)
            waterRemaining = 0;
        else
            waterRemaining -= waterVolume;
    }

    public void useUpBattery(float time) {
        if(time >= batteryRemaining)
            batteryRemaining = 0;
        else
            batteryRemaining -= time;
    }

    public int batteryPercent() {
        return (int)((batteryRemaining * 100) / BATTERY_SIZE);
    }
    public int getCurrentZoneId() {
        return currentZoneId;
    }
    public int getTargetZoneId() { return targetZoneId; }
    public long getLastAnimDurationMs() { return lastAnimDurationMs; }
    public long getAnimStartTime() { return animStartTime; }

    public void setDroneFull() {
        waterRemaining = TANK_SIZE;
        batteryRemaining = BATTERY_SIZE;
    }

    private float timeToZone(Zone dest) {
        Zone origin = new Zone(0, 0, 0, 0, 0); // assume origin at 0,0
        return Zone.getDistance(origin, dest) / DRONE_SPEED;
    }

    private float timeToOrigin(Zone from) {
        Zone origin = new Zone(0, 0, 0, 0, 0);
        return Zone.getDistance(from, origin) / DRONE_SPEED;
    }

    private void sendStatus() {
        try {
            droneSubsystem.sendStatus(droneName, batteryRemaining, currentZoneId, waterRemaining, targetZoneId, lastAnimDurationMs, animStartTime);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    @Override
    public void run() {
        sendStatus(); // initial status
        while(running) {
            try {
                switch(stateMachine.getState()) {
                    case idle:
                        event = droneSubsystem.requestTask(droneName);
                        event.deliverEvent(Event.State.DISPATCHED);
                        stateMachine.handleEvent(DroneEvent.fireAssigned);
                        sendStatus();
                        break;
                    case enRoute: {
                        System.out.println("[" + droneName + "] Enroute to zone " + event.getZoneID());
                        targetZoneId = event.getZoneID();
                        float travelTime = 0;
                        Zone destZone = null;
                        try {
                            destZone = Zone.getZoneFromId(zones, event.getZoneID());
                            travelTime = timeToZone(destZone);
                        } catch (Zone.UnknownZoneException ex) {
                            System.out.println("[" + droneName + "] Zone does not exist " + event.getZoneID());
                        }
                        lastAnimDurationMs = (long)(travelTime * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        if (destZone != null) {
                            System.out.println("[" + droneName + "] Travelling for " + travelTime * 60 + "s");
                            Thread.sleep(lastAnimDurationMs);
                            useUpBattery(travelTime);
                            currentZoneId = destZone.id;
                        }
                        targetZoneId = 0;
                        stateMachine.handleEvent(DroneEvent.arrivedToFire);
                        sendStatus();
                        break;
                    }
                    case droppingAgent:
                        System.out.println("[" + droneName + "] Servicing fire at zone " + event.getZoneID());
                        event.deliverEvent(Event.State.DROPPING);
                        float emptyAmount = event.getWaterLeft();
                        if(emptyAmount > waterRemaining)
                            emptyAmount = waterRemaining;
                        float emptyTime = emptyAmount / DROP_RATE;
                        Thread.sleep((int)(emptyTime * 1000));
                        useUpBattery(emptyTime);
                        useUpWater(emptyAmount);
                        event.useWater(emptyAmount);
                        if(event.getWaterLeft() <= 0) {
                            System.out.println("[" + droneName + "] Fire extinguished");
                            try {
                                droneSubsystem.reportDone(event, droneName);
                            } catch (Exception e) {
                                e.printStackTrace();
                            }
                            event.deliverEvent(Event.State.EXTINGUISHED);
                            event = null;
                            stateMachine.handleEvent(DroneEvent.jobFinished);
                        } else {
                            System.out.println("[" + droneName + "] Tank empty, need refill");
                            event.deliverEvent(Event.State.PARTIAL_EXTINGUISHED);
                            stateMachine.handleEvent(DroneEvent.needRefill);
                            try {
                                droneSubsystem.reportPartialDone(event, droneName);
                            } catch (Exception e) {
                                e.printStackTrace();
                            }
                        }
                        sendStatus();
                        break;
                    case returnForRefill: {
                        float travelTimeToRefill = 0;
                        try {
                            Zone currentZoneV = Zone.getZoneFromId(zones, currentZoneId);
                            travelTimeToRefill = timeToOrigin(currentZoneV);
                        } catch(Zone.UnknownZoneException e) { }
                        lastAnimDurationMs = (long)(travelTimeToRefill * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        System.out.println("[" + droneName + "] Travelling for " + travelTimeToRefill*60 + "s");
                        Thread.sleep(lastAnimDurationMs);
                        useUpBattery(travelTimeToRefill);
                        currentZoneId = 0;
                        float waterNeeded = TANK_SIZE - waterRemaining;
                        long refillMs = (long)((waterNeeded / REFILL_RATE) * 1000);
                        System.out.println("[" + droneName + "] Refilling " + waterNeeded + "L at base");
                        Thread.sleep(refillMs);
                        setDroneFull();
                        stateMachine.handleEvent(DroneEvent.fireAssigned);
                        sendStatus();
                        break;
                    }
                    case returnOrigin: {
                        float travelTimeToOrigin = 0;
                        try {
                            Zone currentZoneV = Zone.getZoneFromId(zones, currentZoneId);
                            travelTimeToOrigin = timeToOrigin(currentZoneV);
                        } catch(Zone.UnknownZoneException e) { }
                        lastAnimDurationMs = (long)(travelTimeToOrigin * 60 * Scheduler.simulationSpeed);
                        animStartTime = System.currentTimeMillis();
                        System.out.println("[" + droneName + "] Travelling for " + travelTimeToOrigin*60 + "s");
                        Thread.sleep(lastAnimDurationMs);
                        useUpBattery(travelTimeToOrigin);
                        currentZoneId = 0;
                        setDroneFull();
                        stateMachine.handleEvent(DroneEvent.arrivedToOrigin);
                        sendStatus();
                        break;
                    }
                    default:
                        System.out.println("[" + droneName + "] Unknown state");
                        break;
                }

            } catch (InterruptedException e) {
                System.out.println("[" + droneName + "] Interrupted");
                running = false;
                Thread.currentThread().interrupt();
            }
        }
    }
}

import java.net.*;
import java.io.*;
import java.util.*;

public class DroneSubsystem implements Runnable {

    private DatagramSocket socket;
    private final List<Zone> zones;
    public final static int NUM_DRONES = 3;
    private final List<Thread> droneThreads;
    private final Queue<Event> taskQueue = new LinkedList<>();
    private final Object taskLock = new Object();

    private static final int SCHEDULER_PORT = 5000;
    private static final int DRONE_PORT = 5002;
    private static final String HOST = "localhost";

    public DroneSubsystem() throws Exception {
        socket = new DatagramSocket(DRONE_PORT);
        zones = Zone.loadFromCSV("SYSC3303-Project-Group5/sample_zone_file.csv");
        droneThreads = new ArrayList<>();
        initializeDrones();
    }

    private void initializeDrones() {
        for(int i = 0; i < NUM_DRONES; i++) {
            String droneName = "Drone-" + i;
            Drone drone = new Drone(this, droneName, zones);
            Thread droneThread = new Thread(drone, droneName);
            droneThreads.add(droneThread);
            droneThread.start();
        }
    }

    private void sendMessage(Message msg) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        ObjectOutputStream out = new ObjectOutputStream(bos);
        out.writeObject(msg);
        out.flush();
        byte[] data = bos.toByteArray();
        DatagramPacket packet = new DatagramPacket(data, data.length, InetAddress.getByName(HOST), SCHEDULER_PORT);
        socket.send(packet);
    }

    private Message receiveMessage() throws Exception {
        byte[] buffer = new byte[4096];
        DatagramPacket packet = new DatagramPacket(buffer, buffer.length);
        socket.receive(packet);
        ByteArrayInputStream bis = new ByteArrayInputStream(packet.getData(), 0, packet.getLength());
        ObjectInputStream in = new ObjectInputStream(bis);
        return (Message) in.readObject();
    }

    public Event requestTask(String droneId) throws InterruptedException {
        try {
            sendMessage(new Message(Message.Type.REQUEST_TASK, null, droneId));
        } catch (Exception e) {
            e.printStackTrace();
        }
        synchronized (taskLock) {
            while (taskQueue.isEmpty()) {
                taskLock.wait();
            }
            return taskQueue.poll();
        }
    }

    public void reportDone(Event event, String droneId) throws Exception {
        sendMessage(new Message(Message.Type.DONE, event, droneId));
    }

    public void sendStatus(String droneId, float battery, int zoneId, float water) throws Exception {
        String note = droneId + "," + battery + "," + zoneId + "," + water;
        sendMessage(new Message(Message.Type.DRONE_STATUS, null, note));
    }

    @Override
    public void run() {
        System.out.println("[DroneSubsystem] Running on port " + DRONE_PORT);
        try {
            while (!Thread.currentThread().isInterrupted()) {
                Message msg = receiveMessage();
                System.out.println("[DroneSubsystem] Received: " + msg);
                if (msg.getType() == Message.Type.DISPATCH) {
                    synchronized (taskLock) {
                        taskQueue.offer(msg.getEvent());
                        taskLock.notifyAll();
                    }
                } else if (msg.getType() == Message.Type.NO_TASK) {
                    // Perhaps wait and retry, but for now, ignore
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        socket.close();
    }

    public static void main(String[] args) throws Exception {
        DroneSubsystem subsystem = new DroneSubsystem();
        new Thread(subsystem).start();
    }
}

import java.net.*;
import java.io.*;
import java.util.*;

public class DroneSubsystem implements Runnable {

    private DatagramSocket socket;
    private final List<Zone> zones;
    public final static int NUM_DRONES = 3;
    private final List<Thread> droneThreads;
    private final Queue<Event> taskQueue = new LinkedList<>();
    private final Object taskLock = new Object();

    private static final int SCHEDULER_PORT = 5000;
    private static final int DRONE_PORT = 5002;
    private static final String HOST = "localhost";

    public DroneSubsystem() throws Exception {
        socket = new DatagramSocket(DRONE_PORT);
        zones = Zone.loadFromCSV("SYSC3303-Project-Group5/sample_zone_file.csv");
        droneThreads = new ArrayList<>();
        initializeDrones();
    }

    private void initializeDrones() {
        for(int i = 0; i < NUM_DRONES; i++) {
            String droneName = "Drone-" + i;
            Drone drone = new Drone(this, droneName, zones);
            Thread droneThread = new Thread(drone, droneName);
            droneThreads.add(droneThread);
            droneThread.start();
        }
    }

    private void sendMessage(Message msg) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        ObjectOutputStream out = new ObjectOutputStream(bos);
        out.writeObject(msg);
        out.flush();
        byte[] data = bos.toByteArray();
        DatagramPacket packet = new DatagramPacket(data, data.length, InetAddress.getByName(HOST), SCHEDULER_PORT);
        socket.send(packet);
    }

    private Message receiveMessage() throws Exception {
        byte[] buffer = new byte[4096];
        DatagramPacket packet = new DatagramPacket(buffer, buffer.length);
        socket.receive(packet);
        ByteArrayInputStream bis = new ByteArrayInputStream(packet.getData(), 0, packet.getLength());
        ObjectInputStream in = new ObjectInputStream(bis);
        return (Message) in.readObject();
    }

    public Event requestTask(String droneId) throws InterruptedException {
        try {
            sendMessage(new Message(Message.Type.REQUEST_TASK, null, droneId));
        } catch (Exception e) {
            e.printStackTrace();
        }
        synchronized (taskLock) {
            while (taskQueue.isEmpty()) {
                taskLock.wait();
            }
            return taskQueue.poll();
        }
    }

    public void reportDone(Event event, String droneId) throws Exception {
        sendMessage(new Message(Message.Type.DONE, event, droneId));
    }

    public void reportPartialDone(Event event, String droneId) throws Exception {
        sendMessage(new Message(Message.Type.PARTIAL_DONE, event, droneId));
    }

    public void sendStatus(String droneId, float battery, int zoneId, float water, int targetZoneId, long lastAnimDurationMs, long animStartTime) throws Exception {
        String note = droneId + "," + battery + "," + zoneId + "," + water + "," + targetZoneId + "," + lastAnimDurationMs + "," + animStartTime;
        sendMessage(new Message(Message.Type.DRONE_STATUS, null, note));
    }

    @Override
    public void run() {
        System.out.println("[DroneSubsystem] Running on port " + DRONE_PORT);
        try {
            while (!Thread.currentThread().isInterrupted()) {
                Message msg = receiveMessage();
                System.out.println("[DroneSubsystem] Received: " + msg);
                if (msg.getType() == Message.Type.DISPATCH) {
                    synchronized (taskLock) {
                        taskQueue.offer(msg.getEvent());
                        taskLock.notifyAll();
                    }
                } else if (msg.getType() == Message.Type.NO_TASK) {
                    // Perhaps wait and retry, but for now, ignore
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        socket.close();
    }

    public static void main(String[] args) throws Exception {
        DroneSubsystem subsystem = new DroneSubsystem();
        new Thread(subsystem).start();
    }
}

import java.io.Serializable;

public class Event implements Serializable {
    public enum EventType {
        FIRE_DETECTED,
        DRONE_REQUEST
    }
    public enum Severity{
        //L of water/foam needed
        LOW(10),
        MODERATE(20),
        HIGH(30);
        private final int waterRequired;
        Severity(int waterRequired){
            this.waterRequired = waterRequired;
        }
        public int getWaterRequired(){
            return waterRequired;
        }
    }
    public enum State {
        INACTIVE,
        EXTINGUISHED,
        PENDING,
        DISPATCHED,
        DROPPING
    }
    //event attrib
    private final String time;
    private final int zoneID;
    private final EventType eventType;
    private final Severity severity;

    private State curState;
    private float waterLeft; //amount of water left to put out the fire

    //event constr
    public Event(String time, int zoneID, EventType eventType, Severity severity){
        this.time = time;
        this.zoneID = zoneID;
        this.eventType = eventType;
        this.severity = severity;
        this.waterLeft = getWaterRequired();
        this.curState = State.INACTIVE;
    }

    //getters
    public String getTime(){
        return time;
    }
    public int getZoneID(){
        return zoneID;
    }
    public EventType getEventType(){
        return eventType;
    }
    public Severity getSeverity(){
        return severity;
    }
    public int getWaterRequired(){
        return severity.getWaterRequired();
    }
    public State currentState() {return curState;}

    public float getWaterLeft(){
        return waterLeft;
    } //get the amount of water left to put out the fire

    public void deliverEvent(State newState) { curState = newState; }
    public void useWater(float waterVolume) { //use water on a fire
        if(waterVolume >= getWaterLeft())
            waterLeft = 0;
        else
            waterLeft -= waterVolume;
    }

    //parse an eventtype from a string
    public static EventType parseEventType(String typeString){
        try{
            return EventType.valueOf(typeString.toUpperCase());
        } catch (IllegalArgumentException e ) {
            throw new IllegalArgumentException("invalid event type" + typeString);
        }
    }
    public static Severity parseSeverity(String servertiyString){
        try{
            return Severity.valueOf(servertiyString.toUpperCase());
        } catch (IllegalArgumentException e){
            throw new IllegalArgumentException("invalid severity level" + servertiyString);
        }
    }
    @Override
    public String toString(){
        return String.format("Event[Time=%s, Zone=%d, Type=%s, Severity=%s (%dL)]", time, zoneID, eventType, severity, severity.getWaterRequired());
    }
}

import java.io.Serializable;

public class Event implements Serializable {
    public enum EventType {
        FIRE_DETECTED,
        DRONE_REQUEST
    }
    public enum Severity{
        //L of water/foam needed
        LOW(10),
        MODERATE(20),
        HIGH(30);
        private final int waterRequired;
        Severity(int waterRequired){
            this.waterRequired = waterRequired;
        }
        public int getWaterRequired(){
            return waterRequired;
        }
    }
    public enum State {
        INACTIVE,
        EXTINGUISHED,
        PENDING,
        DISPATCHED,
        DROPPING,
        PARTIAL_EXTINGUISHED
    }
    //event attrib
    private final String time;
    private final int zoneID;
    private final EventType eventType;
    private final Severity severity;

    private State curState;
    private float waterLeft; //amount of water left to put out the fire

    //event constr
    public Event(String time, int zoneID, EventType eventType, Severity severity){
        this.time = time;
        this.zoneID = zoneID;
        this.eventType = eventType;
        this.severity = severity;
        this.waterLeft = getWaterRequired();
        this.curState = State.INACTIVE;
    }

    //getters
    public String getTime(){
        return time;
    }
    public int getZoneID(){
        return zoneID;
    }
    public EventType getEventType(){
        return eventType;
    }
    public Severity getSeverity(){
        return severity;
    }
    public int getWaterRequired(){
        return severity.getWaterRequired();
    }
    public State currentState() {return curState;}

    public float getWaterLeft(){
        return waterLeft;
    } //get the amount of water left to put out the fire

    public void deliverEvent(State newState) { curState = newState; }
    public void useWater(float waterVolume) { //use water on a fire
        if(waterVolume >= getWaterLeft())
            waterLeft = 0;
        else
            waterLeft -= waterVolume;
    }
    public void setWaterLeft(float waterLeft) { this.waterLeft = waterLeft; }

    //parse an eventtype from a string
    public static EventType parseEventType(String typeString){
        try{
            return EventType.valueOf(typeString.toUpperCase());
        } catch (IllegalArgumentException e ) {
            throw new IllegalArgumentException("invalid event type" + typeString);
        }
    }
    public static Severity parseSeverity(String servertiyString){
        try{
            return Severity.valueOf(servertiyString.toUpperCase());
        } catch (IllegalArgumentException e){
            throw new IllegalArgumentException("invalid severity level" + servertiyString);
        }
    }
    @Override
    public String toString(){
        return String.format("Event[Time=%s, Zone=%d, Type=%s, Severity=%s (%dL)]", time, zoneID, eventType, severity, severity.getWaterRequired());
    }
}

import javax.swing.*;
